-- Canonical system boot-seed (spec §2): what any temper system needs. Namespace-free —
-- every statement resolves against the connection-default schema (`public` in production;
-- ephemeral `public`-schema databases via `#[sqlx::test]` in artifact tests). Mirrors
-- temper_substrate::scenario::bootseed::seed_system, translated to a plain migration.

-- 1. The canonical system actor. Events require a NOT NULL emitter. kb_profiles.handle is UNIQUE;
--    kb_entities has no unique constraint on (profile_id, name), so mirror bootseed's
--    SELECT-then-INSERT existence check instead of ON CONFLICT.
INSERT INTO kb_profiles (handle, display_name, system_access)
VALUES ('system', 'System', 'admin')
ON CONFLICT (handle) DO UPDATE SET display_name = EXCLUDED.display_name;

INSERT INTO kb_entities (profile_id, name, metadata)
SELECT p.id, 'system', '{}'::jsonb
  FROM kb_profiles p
 WHERE p.handle = 'system'
   AND NOT EXISTS (
       SELECT 1 FROM kb_entities e WHERE e.profile_id = p.id AND e.name = 'system'
   );

-- 2. The access-gate settings row (id = 1 CHECK). Without it has_system_access / is_system_admin
--    read an empty CTE and return NULL (spec §2, item 4) — the access gate fails closed-as-NULL.
INSERT INTO kb_system_settings (id, access_mode) VALUES (1, 'open')
ON CONFLICT (id) DO NOTHING;

