ON CONFLICT (name) DO UPDATE
  SET payload_schema = EXCLUDED.payload_schema, schema_version = EXCLUDED.schema_version;

-- 4. The 2 global system lenses (cogmap_id NULL = global), event-sourced via lens_create and
--    attributed to the system entity. lens_create(p_payload jsonb, p_emitter uuid): a NESTED
--    jsonb payload (NOT positional weights). _project_lens_created reads lens_id (minted here),
--    cogmap_id, name, selection_kind ('homed' — bootseed value + column default),
--    weights{express,contains,leads_to,near,prop}, salience{telos,ref,central}, resolution.
--    The salience key the projector reads is `ref` (not `reference`). Weight values are the EXACT
--    vectors from system.yaml (telos-default lines :38, telos-default-propheavy :39).
SELECT lens_create(
  jsonb_build_object(
    'lens_id',        uuid_generate_v7(),
    'cogmap_id',      NULL,
    'name',           'telos-default',
    'selection_kind', 'homed',
    'weights',  jsonb_build_object('express', 1.0, 'contains', 1.0, 'leads_to', 0.6, 'near', 0.3, 'prop', 0.4),
    'salience', jsonb_build_object('telos', 0.5, 'ref', 0.3, 'central', 0.2),
    'resolution',     0.5
  ),
  (SELECT e.id FROM kb_entities e JOIN kb_profiles p ON p.id = e.profile_id
    WHERE p.handle = 'system' AND e.name = 'system')
);

SELECT lens_create(
  jsonb_build_object(
    'lens_id',        uuid_generate_v7(),
    'cogmap_id',      NULL,
    'name',           'telos-default-propheavy',
    'selection_kind', 'homed',
    'weights',  jsonb_build_object('express', 1.0, 'contains', 1.0, 'leads_to', 0.1, 'near', 0.3, 'prop', 1.2),
    'salience', jsonb_build_object('telos', 0.5, 'ref', 0.3, 'central', 0.2),
    'resolution',     0.5
  ),
  (SELECT e.id FROM kb_entities e JOIN kb_profiles p ON p.id = e.profile_id
    WHERE p.handle = 'system' AND e.name = 'system')
);
